int main_driver() {
    std::stringstream ss;
    std::streambuf* oldCout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());

    Teacher teacher1("Alice", "Smith", "Physics");
    teacher1.displayTeacherInfo();

    Teacher teacher2("Bob", "Johnson", "Chemistry");
    teacher2.displayTeacherInfo();

    // Demonstrating the semantic error: deleting a derived object via a base pointer
    // when the base class destructor is not virtual. This will lead to the Teacher's
    // destructor (and thus the deletion of 'grades') not being called, resulting in a memory leak.
    Person* teacherPtr = new Teacher("Charlie", "Brown", "History");
    static_cast<Teacher*>(teacherPtr)->displayTeacherInfo(); // Call method to get output
    delete teacherPtr; // This will only call Person::~Person(), leaking grades.

    std::cout.rdbuf(oldCout);
    std::cout << ss.str();
    return 0;
}
